SELECT count(*) FROM keyword, movie_keyword, title, cast_info, movie_companies, char_name, name, company_type WHERE movie_keyword.keyword_id = keyword.id AND movie_keyword.movie_id = title.id AND cast_info.movie_id = title.id AND movie_companies.movie_id = title.id AND cast_info.person_role_id = char_name.id AND cast_info.person_id = name.id AND movie_companies.company_type_id = company_type.id;